import { useEffect } from 'react'
import { Link } from 'react-router-dom'
import { ChevronRight, Heart, ShoppingBag, Loader2 } from 'lucide-react'
import { Button } from '@/components/ui/button'
import useWishlistStore from '@/stores/useWishlistStore'
import useCartStore from '@/stores/useCartStore'
import useProductStore from '@/stores/useProductStore'
import ProductCard from '@/components/ProductCard'
import { useToast } from '@/hooks/use-toast'

export default function Wishlist() {
  const { items } = useWishlistStore()
  const { addItem } = useCartStore()
  const { products, isLoading, fetchProducts } = useProductStore()
  const { toast } = useToast()

  useEffect(() => {
    fetchProducts()
  }, [fetchProducts])

  const wishlistProducts = products.filter((p) => items.includes(p.id))

  const handleAddToCart = (product: any) => {
    addItem(product)
    toast({
      title: 'Adicionado ao carrinho!',
      description: `${product.title} foi adicionado.`,
    })
  }

  return (
    <div className="container mx-auto px-4 py-8 max-w-7xl">
      <nav className="flex items-center text-sm text-muted-foreground mb-8">
        <Link to="/" className="hover:text-primary transition-colors">
          Home
        </Link>
        <ChevronRight className="w-4 h-4 mx-1" />
        <span className="text-foreground font-medium truncate">Lista de Desejos</span>
      </nav>

      <div className="mb-10">
        <h1 className="text-3xl md:text-5xl font-heading font-bold mb-4 text-foreground flex items-center gap-3">
          <Heart className="w-8 h-8 md:w-10 md:h-10 text-primary fill-primary" />
          Minha Lista de Desejos
        </h1>
        <p className="text-lg text-muted-foreground">
          Seus modelos favoritos salvos para montar depois.
        </p>
      </div>

      {isLoading && products.length === 0 ? (
        <div className="flex items-center justify-center py-24 text-muted-foreground">
          <Loader2 className="w-8 h-8 animate-spin" />
        </div>
      ) : wishlistProducts.length > 0 ? (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-x-6 gap-y-10">
          {wishlistProducts.map((product) => (
            <div key={product.id} className="flex flex-col gap-4">
              <ProductCard product={product} />
              <Button
                onClick={() => handleAddToCart(product)}
                className="w-full mt-auto"
                variant="secondary"
              >
                <ShoppingBag className="w-4 h-4 mr-2" />
                Adicionar ao Carrinho
              </Button>
            </div>
          ))}
        </div>
      ) : (
        <div className="text-center py-24 bg-muted/30 rounded-2xl border border-dashed animate-fade-in">
          <Heart className="w-16 h-16 text-muted-foreground/30 mx-auto mb-6" />
          <h3 className="text-2xl font-heading font-semibold mb-3">Sua lista está vazia</h3>
          <p className="text-muted-foreground mb-8 max-w-md mx-auto">
            Explore nosso catálogo de modelos lowpoly e salve seus favoritos clicando no coração de
            cada produto.
          </p>
          <Button size="lg" asChild>
            <Link to="/">Explorar Catálogo</Link>
          </Button>
        </div>
      )}
    </div>
  )
}
